import asyncio
from typing import List, Callable, Any

class AsyncPipeline:
    def __init__(self):
        self.stages: List[Callable] = []

    def add_stage(self, fn: Callable) -> "AsyncPipeline":
        # If the stage is an async function, we store it such that it can be awaited later.
        # We wrap the callable to ensure consistency although type checking might complain.
        self.stages.append(fn) 
        return self

    async def run(self, items: List[Any]) -> List[Any]:
        results = []
        for item in items:
            value = item
            for stage in self.stages:
                if asyncio.iscoroutinefunction(stage):
                    value = await stage(value) # Await async stages even in sequential run
                else:
                    value = stage(value)     # Call sync stages directly
            results.append(value)
        return results

    async def run_parallel(self, items: List[Any]) -> List[Any]:
        tasks = [self._process(item) for item in items]
        return await asyncio.gather(*tasks)

    async def _process(self, item: Any) -> Any:
        value = item
        for stage in self.stages:
            if asyncio.iscoroutinefunction(stage):
                # FIX: Must await the result of an async function call
                value = await stage(value)
            else:
                # Sync stages called normally
                value = stage(value)
        return value

